24	  it.todo("7 runes → base premium 175 G (no block; 7 = no group of exactly 3 with leftovers)");
25	
26	  // 'Alike' components — same type, not family
27	  it.todo("2 runes + 1 moonstone → base premium 75 G (no block, different types)");
