34	  it.todo("customer with exactly 2 years → loyalty discount applies");
35	  it.todo("sword enchantment exactly 5 → high-enchantment surcharge applies");
36	  it.todo("cursed sword enchantment exactly 5 → both curse and high-enchantment surcharges apply");
37	  it.todo("sword enchantment 4, not cursed → no surcharge");
38	
39	  // Rounding in MHPCO's favor
40	  it.todo("premium 197.5 G → rounded up to 198 G");
