55	  it.todo("dragon sword, ench 9, damage 1000 G → payout 400 G (50% wins, then deductible)");
56	  it.todo("dragon sword, ench 5, damage 800 G → payout 700 G (dragon full, then deductible)");
57	  it.todo("steel sword, ench 9, damage 1000 G → payout 400 G (50% rule, then deductible)");
58	
59	  // Multiple items + deductible per damage event
60	  it.todo("dragon attack on insured sword (500 G) + amulet (300 G) → payout 600 G (deductible per damaged item)");
